    public function importmarks(){

        $missingapplications = \App\Missingapplication::all();
        foreach($missingapplications as $ma){
            $ca= \App\Currentapplicant::where('candidate_id',$ma->id)->get();
            if($ca->count()>0){
                $ma->status = 1;
            }else{
                $ma->status = 0;
            }
            $ma->save();
        }

    }

    public function updatePassword() {
        $users = array(
            array("username" => "HY13", "password" => "tw9f752U")
        );

        foreach ($users as $user) {
            User::where("username", $user["username"])->update([
                "password" => bcrypt($user["password"]),
                "confirmation_code"=> $user["password"]
            ]);
        }
    }

    public function getDecember2019passcandidatemarks() {
        $junexam_id = \App\Exam::where("name", "June 2019")->first()->id;
        $decexam_id = \App\Exam::where("name", "December 2019")->first()->id;

        $academicyear_id = Academicyear::where("year", "2019")->first()->id;

        $approvedprogramme_ids = Approvedprogramme::where("academicyear_id", $academicyear_id)
            ->whereIn("programme_id", Programme::where("numberofterms", 2)->where("recognised_by", "RCI")->where("active_status", "!=", "3")->pluck("id")->toArray())
            ->pluck("id")->toArray();

        $application_ids = Application::whereIn("approvedprogramme_id", $approvedprogramme_ids)->pluck("id")->toArray();
        unset($approvedprogramme_ids);

        $mark_ids = Mark::whereIn("application_id", $application_ids)->pluck("id")->toArray();

        foreach ($mark_ids as $m)
            echo $m." ";
    }

